    // MARK: - Native Bridge JavaScript
    private func createNativeBridgeScript() -> String {
        return """
        (function() {
            // Create native bridge namespace
            window.NativeBridge = {
                // Callback storage
                _callbacks: {},
                _callbackId: 0,
                
                // Internal: send message to native
                _postMessage: function(type, data, callback) {
                    var message = {
                        type: type,
                        data: data || {},
                        callbackId: null
                    };
                    
                    if (callback) {
                        message.callbackId = 'cb_' + (++this._callbackId);
                        this._callbacks[message.callbackId] = callback;
                    }
                    
                    window.webkit.messageHandlers.\(messageHandlerName).postMessage(message);
                },
                
                // Internal: receive callback from native
                _receiveCallback: function(callbackId, result) {
                    var callback = this._callbacks[callbackId];
                    if (callback) {
                        callback(result);
                        delete this._callbacks[callbackId];
                    }
                },
                
                // Internal: receive event from native
                _receiveEvent: function(eventName, data) {
                    var event = new CustomEvent('nativeBridge:' + eventName, { detail: data });
                    window.dispatchEvent(event);
                },
                
                // Public API: Request camera access
                requestCameraAccess: function(callback) {
                    this._postMessage('cameraAccess', {}, callback);
                },
                
                // Public API: Request push notifications
                requestPushNotifications: function(callback) {
                    this._postMessage('pushNotifications', {}, callback);
                },
                
                // Public API: In-app purchase
                purchaseProduct: function(productId, callback) {
                    this._postMessage('inAppPurchase', { productId: productId }, callback);
                },
                
                // Public API: Restore purchases
                restorePurchases: function(callback) {
                    this._postMessage('restorePurchases', {}, callback);
                },
                
                // Public API: Haptic feedback
                hapticFeedback: function(style) {
                    this._postMessage('hapticFeedback', { style: style || 'medium' });
                },
                
                // Public API: Share content
                shareContent: function(title, text, url) {
                    this._postMessage('shareContent', { title: title, text: text, url: url });
                },
                
                // Public API: Get device info
                getDeviceInfo: function(callback) {
                    this._postMessage('getDeviceInfo', {}, callback);
                },
                
                // Platform detection
                isNativeApp: true,
                platform: 'ios'
            };
            
            // Dispatch ready event
            window.dispatchEvent(new CustomEvent('nativeBridgeReady'));
        })();
        """
    }
    
