    // MARK: - Native Functions
    private func handleCameraAccess(callbackId: String?) {
        let status = AVCaptureDevice.authorizationStatus(for: .video)
        
        switch status {
        case .authorized:
            sendCallback(callbackId: callbackId, result: ["granted": true, "status": "authorized"])
            presentCamera()
        case .notDetermined:
            AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
                DispatchQueue.main.async {
                    self?.sendCallback(callbackId: callbackId, result: ["granted": granted, "status": granted ? "authorized" : "denied"])
                    if granted {
                        self?.presentCamera()
                    }
                }
            }
        case .denied, .restricted:
            sendCallback(callbackId: callbackId, result: ["granted": false, "status": "denied"])
            showSettingsAlert(message: "Camera access is required. Please enable it in Settings.")
        @unknown default:
            sendCallback(callbackId: callbackId, result: ["granted": false, "status": "unknown"])
        }
    }
    
