    // MARK: - JavaScript Communication
    private func sendCallback(callbackId: String?, result: [String: Any]) {
        guard let callbackId = callbackId else { return }
        
        guard let jsonData = try? JSONSerialization.data(withJSONObject: result),
              let jsonString = String(data: jsonData, encoding: .utf8) else { return }
        
        let js = "window.NativeBridge._receiveCallback('\(callbackId)', \(jsonString));"
        
        DispatchQueue.main.async { [weak self] in
            self?.webView.evaluateJavaScript(js) { _, error in
                if let error = error {
                    print("Error sending callback: \(error.localizedDescription)")
                }
            }
        }
    }
    
    private func sendEvent(name: String, data: [String: Any]) {
        guard let jsonData = try? JSONSerialization.data(withJSONObject: data),
              let jsonString = String(data: jsonData, encoding: .utf8) else { return }
        
        let js = "window.NativeBridge._receiveEvent('\(name)', \(jsonString));"
        
        DispatchQueue.main.async { [weak self] in
            self?.webView.evaluateJavaScript(js) { _, error in
                if let error = error {
                    print("Error sending event: \(error.localizedDescription)")
                }
            }
        }
    }
    
