// MARK: - WKScriptMessageHandler
extension HybridWebViewController: WKScriptMessageHandler {
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard message.name == messageHandlerName,
              let body = message.body as? [String: Any],
              let typeString = body["type"] as? String else {
            print("Invalid message received")
            return
        }
        
        let data = body["data"] as? [String: Any] ?? [:]
        let callbackId = body["callbackId"] as? String
        
        guard let messageType = NativeMessageType(rawValue: typeString) else {
            print("Unknown message type: \(typeString)")
            sendCallback(callbackId: callbackId, result: ["error": "Unknown message type: \(typeString)"])
            return
        }
        
        switch messageType {
        case .cameraAccess:
            handleCameraAccess(callbackId: callbackId)
            
        case .pushNotifications:
            handlePushNotifications(callbackId: callbackId)
            
        case .inAppPurchase:
            if let productId = data["productId"] as? String {
                handleInAppPurchase(productId: productId, callbackId: callbackId)
            } else {
                sendCallback(callbackId: callbackId, result: ["success": false, "error": "Missing productId"])
            }
            
        case .restorePurchases:
            handleRestorePurchases(callbackId: callbackId)
            
        case .hapticFeedback:
            let style = data["style"] as? String ?? "medium"
            handleHapticFeedback(style: style)
            
        case .shareContent:
            handleShareContent(
                title: data["title"] as? String,
                text: data["text"] as? String,
                url: data["url"] as? String
            )
            
        case .getDeviceInfo:
            handleGetDeviceInfo(callbackId: callbackId)
        }
    }
}

// MARK: - WKNavigationDelegate
extension HybridWebViewController: WKNavigationDelegate {
    func webView(_ webView: WKWebView, didStartProvisionalNavigation navigation: WKNavigation!) {
        activityIndicator.startAnimating()
        progressView.isHidden = false
    }
    
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        activityIndicator.stopAnimating()
        progressView.isHidden = true
        webView.scrollView.refreshControl?.endRefreshing()
    }
    
    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        activityIndicator.stopAnimating()
        progressView.isHidden = true
        webView.scrollView.refreshControl?.endRefreshing()
        handleWebViewError(error)
    }
    
    func webView(_ webView: WKWebView, didFailProvisionalNavigation navigation: WKNavigation!, withError error: Error) {
        activityIndicator.stopAnimating()
        progressView.isHidden = true
        webView.scrollView.refreshControl?.endRefreshing()
        handleWebViewError(error)
    }
    
    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        guard let url = navigationAction.request.url else {
            decisionHandler(.cancel)
            return
        }
        
        // Handle external links (open in Safari)
        if let host = url.host, let websiteHost = URL(string: websiteURL)?.host {
            if host != websiteHost && navigationAction.navigationType == .linkActivated {
                // Open external links in Safari
                if ["http", "https"].contains(url.scheme?.lowercased()) {
                    UIApplication.shared.open(url)
                    decisionHandler(.cancel)
                    return
                }
            }
        }
        
        // Handle special URL schemes
        let scheme = url.scheme?.lowercased() ?? ""
        if ["tel", "mailto", "sms", "facetime"].contains(scheme) {
            UIApplication.shared.open(url)
            decisionHandler(.cancel)
            return
        }
        
        // Handle app-specific deep links
        if scheme == "myapp" {
            handleDeepLink(url: url)
            decisionHandler(.cancel)
            return
        }
        
        decisionHandler(.allow)
    }
    
    func webView(_ webView: WKWebView, decidePolicyFor navigationResponse: WKNavigationResponse, decisionHandler: @escaping (WKNavigationResponsePolicy) -> Void) {
        if let httpResponse = navigationResponse.response as? HTTPURLResponse {
            if httpResponse.statusCode >= 400 {
                print("HTTP Error: \(httpResponse.statusCode)")
            }
        }
        decisionHandler(.allow)
    }
    
    private func handleWebViewError(_ error: Error) {
        let nsError = error as NSError
        
        // Ignore cancelled requests
        if nsError.code == NSURLErrorCancelled { return }
        
        // Show offline page for network errors
        if nsError.code == NSURLErrorNotConnectedToInternet ||
            nsError.code == NSURLErrorNetworkConnectionLost {
            loadOfflinePage()
            return
        }
        
        showErrorAlert(message: "Failed to load: \(error.localizedDescription)")
    }
    
    private func loadOfflinePage() {
        let html = """
        <!DOCTYPE html>
        <html>
        <head>
            <meta name="viewport" content="width=device-width, initial-scale=1.0">
            <style>
                body {
                    font-family: -apple-system, BlinkMacSystemFont, sans-serif;
                    display: flex;
                    justify-content: center;
                    align-items: center;
                    height: 100vh;
                    margin: 0;
                    background-color: #f5f5f5;
                    color: #333;
                    text-align: center;
                }
                .container { padding: 20px; }
                h1 { font-size: 24px; margin-bottom: 10px; }
                p { font-size: 16px; color: #666; }
                button {
                    margin-top: 20px;
                    padding: 12px 24px;
                    font-size: 16px;
                    background-color: #007AFF;
                    color: white;
                    border: none;
                    border-radius: 8px;
                    cursor: pointer;
                }
            </style>
        </head>
        <body>
            <div class="container">
                <h1>📡 No Connection</h1>
                <p>Please check your internet connection and try again.</p>
                <button onclick="window.location.reload()">Retry</button>
            </div>
        </body>
        </html>
        """
        webView.loadHTMLString(html, baseURL: nil)
    }
    
    private func handleDeepLink(url: URL) {
        // Handle app-specific deep links
        print("Deep link received: \(url)")
        sendEvent(name: "deepLink", data: ["url": url.absoluteString])
    }
}

// MARK: - WKUIDelegate
extension HybridWebViewController: WKUIDelegate {
    // Handle JavaScript alerts
    func webView(_ webView: WKWebView, runJavaScriptAlertPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping () -> Void) {
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler()
        })
        present(alert, animated: true)
    }
    
    // Handle JavaScript confirms
    func webView(_ webView: WKWebView, runJavaScriptConfirmPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (Bool) -> Void) {
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(false)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(true)
        })
        present(alert, animated: true)
    }
    
    // Handle JavaScript text inputs
    func webView(_ webView: WKWebView, runJavaScriptTextInputPanelWithPrompt prompt: String, defaultText: String?, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (String?) -> Void) {
        let alert = UIAlertController(title: nil, message: prompt, preferredStyle: .alert)
        alert.addTextField { textField in
            textField.text = defaultText
        }
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(nil)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(alert.textFields?.first?.text)
        })
        present(alert, animated: true)
    }
    
    // Handle new window requests (target="_blank")
    func webView(_ webView: WKWebView, createWebViewWith configuration: WKWebViewConfiguration, for navigationAction: WKNavigationAction, windowFeatures: WKWindowFeatures) -> WKWebView? {
        if navigationAction.targetFrame == nil || !(navigationAction.targetFrame?.isMainFrame ?? false) {
            webView.load(navigationAction.request)
        }
        return nil
    }
}

// MARK: - SKProductsRequestDelegate
extension HybridWebViewController: SKProductsRequestDelegate {
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        availableProducts = response.products
        
        if let product = response.products.first {
            let payment = SKPayment(product: product)
            SKPaymentQueue.default().add(payment)
        } else {
            // No products found
            for invalidId in response.invalidProductIdentifiers {
                if let callbackId = purchaseCallbacks[invalidId] {
                    sendCallback(callbackId: callbackId, result: [
                        "success": false,
                        "error": "Product not found: \(invalidId)"
                    ])
                    purchaseCallbacks.removeValue(forKey: invalidId)
                }
            }
        }
    }
    
    func request(_ request: SKRequest, didFailWithError error: Error) {
        print("Product request failed: \(error.localizedDescription)")
        // Notify all pending purchase callbacks
        for (_, callbackId) in purchaseCallbacks {
            sendCallback(callbackId: callbackId, result: [
                "success": false,
                "error": error.localizedDescription
            ])
        }
        purchaseCallbacks.removeAll()
    }
}

// MARK: - SKPaymentTransactionObserver
extension HybridWebViewController: SKPaymentTransactionObserver {
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            let productId = transaction.payment.productIdentifier
            let callbackId = purchaseCallbacks[productId]
            
            switch transaction.transactionState {
            case .purchased:
                // Verify receipt and complete
                let receiptData = getReceiptData()
                sendCallback(callbackId: callbackId, result: [
                    "success": true,
                    "productId": productId,
                    "transactionId": transaction.transactionIdentifier ?? "",
                    "receipt": receiptData ?? ""
                ])
                sendEvent(name: "purchaseCompleted", data: [
                    "productId": productId,
                    "transactionId": transaction.transactionIdentifier ?? ""
                ])
                purchaseCallbacks.removeValue(forKey: productId)
                SKPaymentQueue.default().finishTransaction(transaction)
                
            case .failed:
                let errorMessage = transaction.error?.localizedDescription ?? "Purchase failed"
                sendCallback(callbackId: callbackId, result: [
                    "success": false,
                    "error": errorMessage,
                    "productId": productId
                ])
                sendEvent(name: "purchaseFailed", data: [
                    "productId": productId,
                    "error": errorMessage
                ])
                purchaseCallbacks.removeValue(forKey: productId)
                SKPaymentQueue.default().finishTransaction(transaction)
                
            case .restored:
                sendEvent(name: "purchaseRestored", data: [
                    "productId": productId,
                    "transactionId": transaction.transactionIdentifier ?? "",
                    "originalTransactionId": transaction.original?.transactionIdentifier ?? ""
                ])
                SKPaymentQueue.default().finishTransaction(transaction)
                
            case .deferred:
                sendCallback(callbackId: callbackId, result: [
                    "success": false,
                    "deferred": true,
                    "productId": productId,
                    "message": "Purchase is pending approval"
                ])
                
            case .purchasing:
                break
                
            @unknown default:
                break
            }
        }
    }
    
    func paymentQueueRestoreCompletedTransactionsFinished(_ queue: SKPaymentQueue) {
        let restoredProducts = queue.transactions
            .filter { $0.transactionState == .restored }
            .map { $0.payment.productIdentifier }
        
        sendCallback(callbackId: restoreCallbackId, result: [
            "success": true,
            "restoredProducts": restoredProducts
        ])
        restoreCallbackId = nil
    }
    
    func paymentQueue(_ queue: SKPaymentQueue, restoreCompletedTransactionsFailedWithError error: Error) {
        sendCallback(callbackId: restoreCallbackId, result: [
            "success": false,
            "error": error.localizedDescription
        ])
        restoreCallbackId = nil
    }
    
    private func getReceiptData() -> String? {
        guard let receiptURL = Bundle.main.appStoreReceiptURL,
              FileManager.default.fileExists(atPath: receiptURL.path),
              let receiptData = try? Data(contentsOf: receiptURL) else {
            return nil
        }
        return receiptData.base64EncodedString()
    }
}

// MARK: - UIImagePickerControllerDelegate
extension HybridWebViewController: UIImagePickerControllerDelegate, UINavigationControllerDelegate {
    func imagePickerController(_ picker: UIImagePickerController, didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey : Any]) {
        picker.dismiss(animated: true)
        
        if let image = info[.editedImage] as? UIImage ?? info[.originalImage] as? UIImage {
            // Convert to base64 and send to web
            if let imageData = image.jpegData(compressionQuality: 0.8) {
                let base64String = imageData.base64EncodedString()
                sendEvent(name: "cameraCaptured", data: [
                    "image": "data:image/jpeg;base64,\(base64String)",
                    "width": image.size.width,
                    "height": image.size.height
                ])
            }
        }
    }
    
    func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
        picker.dismiss(animated: true)
        sendEvent(name: "cameraCancelled", data: [:])
    }
}

// MARK: - LeakAvoider (prevents retain cycle with WKUserContentController)
class LeakAvoider: NSObject, WKScriptMessageHandler {
    weak var delegate: WKScriptMessageHandler?
    
    init(delegate: WKScriptMessageHandler) {
        self.delegate = delegate
        super.init()
    }
    
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        delegate?.userContentController(userContentController, didReceive: message)
    }
}

// MARK: - AppDelegate Integration Helper
extension HybridWebViewController {
    /// Call this from AppDelegate when push token is received
    func didRegisterForRemoteNotifications(withDeviceToken deviceToken: Data) {
        let token = deviceToken.map { String(format: "%02.2hhx", $0) }.joined()
        handlePushNotificationToken(token)
    }
}